/** @brief Element is added for HLL calculation. */
template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  if (dense_bucket_.empty()) {
    return;
  }

  // Hash the value
  hash_t hash_val = CalculateHash(val);

  // Get number of leading bits
  uint64_t num_buckets = dense_bucket_.size();
  uint64_t num_bits = 0;
  uint64_t temp = num_buckets - 1;
  while (temp > 0) {
    num_bits++;
    temp >>= 1;
  }

  // Extract bucket index from first num_bits
  uint64_t mask = (1ULL << num_bits) - 1;
  uint64_t bucket_idx = hash_val & mask;

  // Extract the remaining bits
  hash_t remaining_bits = hash_val >> num_bits;

  // Find position of leftmost 1 bit
  uint64_t pos = 0;
  hash_t temp_bits = remaining_bits;
  while (temp_bits > 0) {
    pos++;
    temp_bits >>= 1;
  }
  if (remaining_bits == 0) {
    pos = 65;  // If no 1 bit found
  }

  // Update dense and overflow buckets
  uint64_t dense_val = pos & 0xF;  // Lower 4 bits
  uint64_t overflow_val = pos >> 4;  // Higher bits

  // Update dense bucket
  if (dense_val > dense_bucket_[bucket_idx].to_ullong()) {
    dense_bucket_[bucket_idx] = std::bitset<DENSE_BUCKET_SIZE>(dense_val);
    overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_val);
  } else if (dense_val == dense_bucket_[bucket_idx].to_ullong() &&
             overflow_val > overflow_bucket_[bucket_idx].to_ullong()) {
    overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_val);
  }
}

