/** @brief Function to compute cardinality. */
template <typename T>
auto HyperLogLogPresto<T>::ComputeCardinality() -> void {
  if (dense_bucket_.empty()) {
    cardinality_ = 0;
    return;
  }

  // Calculate the number of buckets
  uint64_t m = dense_bucket_.size();

  // Calculate the sum of 2^-position
  double sum = 0.0;
  for (size_t i = 0; i < dense_bucket_.size(); ++i) {
    uint64_t dense_val = dense_bucket_[i].to_ullong();
    uint64_t overflow_val = overflow_bucket_[i].to_ullong();

    // Reconstruct position from dense and overflow buckets
    uint64_t pos = (overflow_val << 4) | dense_val;

    sum += std::pow(2.0, -static_cast<double>(pos));
  }

  // Apply the HyperLogLog formula
  double raw_estimate = CONSTANT * m * m / sum;

  // Apply bias correction for small and large cardinalities
  cardinality_ = static_cast<uint64_t>(raw_estimate);
}

