#include <cstring>

// Simulate HashBytes from bustub
using hash_t = std::size_t;

hash_t HashBytes(const char *bytes, size_t length) {
    hash_t hash = length;
    for (size_t i = 0; i < length; ++i) {
        hash = ((hash << 5) ^ (hash >> 27)) ^ static_cast<signed char>(bytes[i]);
    }
    return hash;
}

int main() {
    // Test hashing of integer 0
    int64_t val = 0;
    hash_t h = HashBytes(reinterpret_cast<char*>(&val), sizeof(int64_t));
    std::cout << "Hash of 0: " << h << " (hex: " << std::hex << h << std::dec << ")" << std::endl;

    // Test hashing of integer 1
    val = 1;
    h = HashBytes(reinterpret_cast<char*>(&val), sizeof(int64_t));
    std::cout << "Hash of 1: " << h << " (hex: " << std::hex << h << std::dec << ")" << std::endl;

    // For n_bits=3, bucket_idx and remaining_bits
    val = 0;
    h = HashBytes(reinterpret_cast<char*>(&val), sizeof(int64_t));
    uint64_t bucket_idx = h & 7;  // n_bits=3
    uint64_t remaining = h >> 3;
    std::cout << "Hash 0: bucket=" << bucket_idx << ", remaining=" << remaining << " (hex: " << std::hex << remaining << std::dec << ")" << std::endl;

    // Position of leftmost 1
    if (remaining == 0) {
        std::cout << "Position: 65" << std::endl;
    } else {
        uint64_t pos = __builtin_clzll(remaining) + 1;
        std::cout << "Position: " << pos << std::endl;
    }

    return 0;
}
