#include <iostream>
#include <string>
#include <cmath>
#include <cstring>

using hash_t = std::size_t;

hash_t HashBytes(const char *bytes, size_t length) {
    hash_t hash = length;
    for (size_t i = 0; i < length; ++i) {
        hash = ((hash << 5) ^ (hash >> 27)) ^ static_cast<signed char>(bytes[i]);
    }
    return hash;
}

int main() {
    // Test the string hashes from BasicTest1
    std::string strings[] = {
        "Welcome to CMU DB (15-445/645)",
        "Andy", "Connor", "J-How", "Kunle", "Lan", "Prashanth", "William", "Yash", "Yuanxin"
    };

    int bucket_counts[2] = {0, 0};
    int position_counts[2] = {0, 0};

    for (const auto& str : strings) {
        hash_t h = HashBytes(str.data(), str.length());
        uint64_t bucket = h & 1;  // n_bits=1
        uint64_t remaining = h >> 1;

        int pos;
        if (remaining == 0) {
            pos = 65;
        } else {
            pos = __builtin_clzll(remaining) + 1;
        }

        std::cout << "\"" << str << "\" -> bucket=" << bucket << ", pos=" << pos << std::endl;
        bucket_counts[bucket]++;
        position_counts[bucket] = (pos > position_counts[bucket]) ? pos : position_counts[bucket];
    }

    std::cout << "\nBucket 0: count=" << bucket_counts[0] << ", max_pos=" << position_counts[0] << std::endl;
    std::cout << "Bucket 1: count=" << bucket_counts[1] << ", max_pos=" << position_counts[1] << std::endl;

    double sum = std::pow(2.0, -position_counts[0]) + std::pow(2.0, -position_counts[1]);
    double card = 0.79402 * 2 * 2 / sum;
    std::cout << "Sum: " << sum << std::endl;
    std::cout << "Cardinality: " << (size_t)card << std::endl;

    return 0;
}
