#include <iostream>
#include <cmath>

// Test what position values would give us the expected cardinalities

int main() {
    // BasicTest1: n_bits=1, m=2 buckets
    // With 1 element: expect cardinality = 2
    // Assume position in both buckets: sum = 2^-p1 + 2^-p2
    // If both have same position p: sum = 2 * 2^-p = 2^(1-p)
    // cardinality = 0.79402 * 4 / 2^(1-p) = 0.79402 * 4 * 2^(p-1) = 0.79402 * 2 * 2^p
    // For cardinality = 2: 2 = 0.79402 * 2 * 2^p
    // 1 = 0.79402 * 2^p
    // 2^p = 1 / 0.79402 = 1.259
    // p = log2(1.259) = 0.33

    double p = std::log2(1.0 / 0.79402);
    std::cout << "Position for cardinality 2 (after 1 element): " << p << std::endl;

    // But positions must be integers. If p ~ 0.33, that rounds to 0 or 1.
    // With p=1: cardinality = 0.79402 * 2 * 2^1 = 3.18
    // With p=0: cardinality = 0.79402 * 2 * 2^0 = 1.59
    // Neither matches 2.

    // Maybe the formula is different?
    // What if it's: cardinality = m^2 / sum (without the constant)?
    // Then: 2 = 4 / sum, so sum = 2
    // If both buckets have position p: sum = 2 * 2^-p = 2, so 2^-p = 1, so p = 0
    // But what if only one bucket has a position (the other has no elements)?
    // Then sum = 2^-p + others

    // Or what if the formula is: cardinality = m^2 / (sum of 2^-M[i]) ?
    // And what if one bucket always starts with register value 1 or something?

    // Let's try: if one bucket has value p and the other has value 0:
    // sum = 2^-p + 2^0 = 2^-p + 1
    // cardinality = 4 * CONSTANT / (2^-p + 1)
    // For cardinality = 2:  2 = 4 * 0.79402 / (2^-p + 1)
    // 2 * (2^-p + 1) = 4 * 0.79402
    // 2^-p + 1 = 1.588
    // 2^-p = 0.588
    // p = -log2(0.588) = 0.76, round to 1

    // With p = 1: cardinality = 4 * 0.79402 / (0.5 + 1) = 3.176 / 1.5 = 2.117 ≈ 2

    std::cout << "This matches! So position values should be low (0-2 range)" << std::endl;
    std::cout << "But I'm calculating positions of 43-50, which is way too high!" << std::endl;

    return 0;
}
